const r={name:"Rödkål",icon:"rodkal",family:"Korsblommiga",familyLatin:"Brassicaceae",difficulty:"Medel",difficultyWhy:"Rödkål är snäll men bestämd - hon vill ha kalkrik jord, jämn fukt och skydd mot kålfjärilen. Ger du henne det belönar hon dig med vackert lila huvuden som håller långt in på vintern. Lite mer krävande än sallat, men absolut överkomligt.",zones:{outdoor:[1,2,3,4,5,6,7,8],indoor:null,greenhouse:[1,2,3,4,5,6,7,8]},days:"70-150",spacing:"40-50 cm",rowSpacing:"50-60 cm",depth:"1-2 cm",ph:{min:6.5,max:7.5,ideal:7},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Minst 6 timmar sol per dag. Rödkål behöver ordentligt med ljus för att bygga täta huvuden och utveckla den djupa, violetta färgen. I halvskugga blir både huvudena och färgen svagare."},temperature:{min:-5,max:25,ideal:"15-18°C",detail:"Rödkål är en sval tjej som trivs bäst runt 15-18°C. Hon tål frost ner till -5°C och kan stå kvar i landet långt in på hösten. Över 25°C stressar hon och färgutvecklingen hämmas."},wind:{level:"Skyddat",detail:"Precis som sin kusin vitkålen bygger rödkål tunga huvuden som kan fånga vind. Ge henne lite vindskydd eller kupa jord runt stambasen."}},watering:{need:"Medel-Hög",icon:"water",summary:"Rödkål vill ha jämn fukt hela säsongen. Ojämn vattning kan få huvudena att spricka - och en sprucken rödkål tappar snabbt sin fina färg.",phases:[{phase:"Förodling (0-6 veckor)",need:"Medel",tip:"Håll jorden jämnt fuktig men aldrig blöt. Kålfrön gror snabbt (5-10 dagar) vid rumstemperatur."},{phase:"Etablering (utplantering)",need:"Hög",tip:"Vattna rikligt vid utplantering och dagligen den första veckan. Nyplanterade kålplantor behöver extra omsorg för att sätta sig."},{phase:"Tillväxt och bladbildning",need:"Medel-Hög",tip:"Djupvattna 2-3 gånger i veckan. Nu bygger hon bladmassan som ska bli det vackra lila huvudet."},{phase:"Huvudbildning och mognad",need:"Hög",tip:"Kritisk period! Håll jämn fukt - plötsligt regn efter torka kan få huvudena att spricka. Hellre lite och ofta."}],mistakes:["Ojämn vattning - torka följt av storvattning gör att huvudena spricker. Det klassiska nybörjarmisstaget.","Vattna ovanifrån sent på kvällen - fuktiga blad i mörkret bjuder in svampsjukdomar","Tro att hon klarar sig själv bara för att hon ser tålig ut - speciellt under huvudbildningen behöver hon jämn fukt","Sluta vattna för tidigt på hösten - sena lagringssorter behöver fukt ända till skörd"],tip:"Mulcha ordentligt med gräsklipp eller halm runt plantorna. Det håller jorden fuktig och sval, och minskar risken för de plötsliga fuktsvängningar som får huvudena att spricka."},soil:"Näringsrik, kalkrik, mullrik jord med bra struktur. Rödkål är en storätare som vill ha djup, bra jord. Kalkrik jord är extra viktigt - det skyddar mot klumprotsjuka och påverkar faktiskt färgen positivt.",soilTips:["Kalka på hösten om pH är under 6.5 - rödkål ÄLSKAR kalkrik jord. Hög pH ger dessutom mer blåviolett färg, medan sur jord gör henne rödare.","Blanda in rikligt med brunnen kompost och gärna lite hönsgödsel innan plantering. Rödkål är hungrig som en tonåring.","Undvik packad jord - luckra djupt och blanda in sand om du har tung lera. Rötterna vill ner ordentligt."],timeline:{1:[{phase:"Förodla inomhus",months:"Feb-Mar",icon:"seedling"},{phase:"Plantera ut",months:"Apr-Maj",icon:"leaf"},{phase:"Gödsla",months:"Maj-Jun",icon:"water"},{phase:"Skörd tidiga sorter",months:"Jun-Jul",icon:"harvest"},{phase:"Skörd sena sorter",months:"Sep-Nov",icon:"harvest"}],4:[{phase:"Förodla inomhus",months:"Mar-Apr",icon:"seedling"},{phase:"Plantera ut",months:"Maj-Jun",icon:"leaf"},{phase:"Gödsla",months:"Jun-Jul",icon:"water"},{phase:"Skörd tidiga sorter",months:"Jul-Aug",icon:"harvest"},{phase:"Skörd sena sorter",months:"Okt-Nov",icon:"harvest"}],6:[{phase:"Förodla inomhus",months:"Apr",icon:"seedling"},{phase:"Plantera ut",months:"Jun",icon:"leaf"},{phase:"Gödsla",months:"Jun-Jul",icon:"water"},{phase:"Skörd tidiga sorter",months:"Aug-Sep",icon:"harvest"},{phase:"Skörd sena sorter",months:"Sep-Okt",icon:"harvest"}]},nutritionData:[{month:"Mar",N:20,P:10,K:10,label:"Förodling"},{month:"Apr",N:30,P:15,K:10,label:"Tillväxtstart"},{month:"Maj",N:60,P:25,K:20,label:"Utplantering"},{month:"Jun",N:85,P:35,K:30,label:"Kraftig bladtillväxt"},{month:"Jul",N:90,P:40,K:45,label:"Huvudbildning"},{month:"Aug",N:70,P:35,K:50,label:"Mognad"},{month:"Sep",N:40,P:25,K:40,label:"Sena sorter mognar"},{month:"Okt",N:15,P:15,K:25,label:"Lagringskål skördas"}],nutritionTips:[{timing:"Vid plantering",tip:"Grundgödsla med brunnen kompost och hornmjöl. Rödkål behöver en kväverik start för att bygga de stora ytterbladen som ska forma huvudet."},{timing:"Tre veckor efter utplantering",tip:"Ge flytande nässelvatten eller alggödsel. Hon ska vara i full gång nu och behöver ordentligt med näring."},{timing:"Vid huvudbildning",tip:"Extra giva med kaliumrik gödsel (vedaska eller alggödsel). Kalium hjälper huvudet att bli tätt och stärker den fina lila färgen."},{timing:"Sensommar (sena sorter)",tip:"En sista lätt giva med kalium stärker cellväggarna och gör kålen mer motståndskraftig mot frost. Bra för lagringsegenskaperna."}],companions:{good:[{id:"lok",name:"Lök",icon:"vegetable",why:"Lökens starka doft förvirrar kålfjärilen - hon hittar inte kålen bland all lökdoft. Ett beprövat försvar som funkar."},{id:"dill",name:"Dill",icon:"herb",why:"Lockar parasitsteklar som äter kålfjärilens larver. Dillen jobbar som rödkålens personliga livvakt."},{id:"selleri",name:"Selleri",icon:"vegetable",why:"Sellerins starka doft maskerar kålen för skadedjur. De trivs fint ihop i samma bädd."},{id:"rodbeta",name:"Rödbeta",icon:"vegetable",why:"Tar näring från ett annat djup i jorden - de konkurrerar inte utan kompletterar varandra."}],bad:[{id:"jordgubbar",name:"Jordgubbar",icon:"berry",why:"Jordgubbar hämmas av kålväxter. De trivs verkligen inte ihop - håll dem åtskilda."},{id:"tomat",name:"Tomat",icon:"vegetable",why:"Båda är storätare som slåss om samma näring. Ingen av dem blir nöjd."},{name:"Andra kålväxter",icon:"vegetable",why:"Odla inte rödkål bredvid annan kål - de delar skadedjur och sjukdomar och förstärker problemen."}]},rotation:{avoid:[{id:"gronkal",name:"Grönkål"},{id:"blomkal",name:"Blomkål"},{id:"broccoli",name:"Broccoli"},{id:"vitkal",name:"Vitkål"},{id:"brysselkal",name:"Brysselkål"},{id:"kalrabbi",name:"Kålrabbi"},{id:"radisa",name:"Rädisa"},{id:"pak-choi",name:"Pak choi"}],avoidWhy:"Alla tillhör korsblommiga och delar sjukdomar som klumprotsjuka. Vänta minst 4 år - helst 6-7 år - innan du odlar kål på samma plats igen. Klumprotsjuka lever kvar i jorden extremt länge.",goodBefore:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"},{id:"potatis",name:"Potatis"},{id:"lok",name:"Lök"}],goodBeforeWhy:"Baljväxter fixerar kväve i jorden - gratis gödsel för hungriga rödkål! Potatis och lök lämnar ren, väl bearbetad jord.",goodAfter:[{id:"morot",name:"Morot"},{id:"lok",name:"Lök"},{id:"sallat",name:"Sallat"},{id:"rodbeta",name:"Rödbeta"}],goodAfterWhy:"Rotgrönsaker trivs i den djupt bearbetade, näringsrika restjorden efter kål. Sallat gillar kvävet som kålen lämnar efter sig."},varieties:[{name:"Langedijker Bewaar 2",zones:[1,2,3,4,5],note:"Klassisk holländsk lagringssort med stora, fasta huvuden. Håller hela vintern i källaren. Djupt violett färg och mild smak. Finns hos Nelson Garden och Svedberga."},{name:"Rodynda",zones:[1,2,3,4,5,6],note:"Tidig-medelsort (Kultursaat) med runda, jämna huvuden på 2-3 kg. Pålitlig och lättodlad med fin färg. Ekofrö hos Lindbloms (demeter/eko)."},{name:"Kalibos",zones:[1,2,3,4,5],note:"Unik spetskålsform med lös struktur - perfekt för sallader! Mildare smak än runda sorter och vackert rubinröd. Ekofrö hos Runåbergs."},{name:"Integro F1",zones:[1,2,3,4,5,6],note:"F1-hybrid med mycket jämna huvuden och bra sjukdomsresistens. Ger pålitliga resultat men fröna kan inte sparas. Ekofrö hos Semenco."}],problems:[{name:"Kålfjäril",symptom:"Gröna larver som tuggar stora hål i bladen. Lämnar gröna spillningshögar och kan förstöra hela plantor på kort tid.",fix:"Fiberduk från dag ett - det enda helt säkra skyddet! Handplocka larver regelbundet. Spruta med Bacillus thuringiensis (Bt) mot larverna. Samodla med dill och lök för att förvirra fjärilarna. Pudra med stenmjöl på fuktiga blad."},{name:"Kålfluga",symptom:"Plantan vissnar trots vattning. Dra upp en och titta - rötterna är fulla av vita larver som äter sig igenom rotsystemet.",fix:"Kålkragar runt stjälken vid utplantering - hindrar flugan från att lägga ägg vid stambasen. Fiberduk hjälper också. Kraftiga plantor med bra rotsystem klarar lättare angrepp."},{name:"Klumprotsjuka",symptom:"Plantan stannar i tillväxt och vissnar i värme. Rötterna har fula, klumpiga svullnader. Det här är kålodlarens mardröm.",fix:"Ingen bot - dra upp och bränn angripna plantor! Kalka jorden ordentligt (pH över 7). Odla inte kål på samma plats på minst 6-7 år. Svampen överlever i jorden extremt länge."},{name:"Spruckna huvuden",symptom:"Huvudet spricker mitt i mognadsfasen, ofta efter en period av torka följd av kraftigt regn.",fix:"Nästan alltid orsakat av ojämn vattning. Mulcha och håll jämn fukt. Vrid plantan ett kvarts varv för att bryta några rötter och bromsa tillväxten om du inte hinner skörda i tid."}],goodToKnow:[{icon:"warning",title:"Kalka - klumprotsjukans fiende",text:"Det absolut viktigaste du kan göra för kål är att kalka jorden. Klumprotsjuka trivs i sur jord och finns den väl i marken stannar den i 7+ år. Kalka på hösten, sikta på pH runt 7.",severity:"warning"},{icon:"leaf",title:"Färgen avslöjar jordens pH",text:"Rödkålens färg påverkas av jordens surhet! I alkalisk jord (hög pH) blir hon mer blåviolett, i sur jord mer röd. Det är samma kemi som gör att rödkål kan användas som pH-indikator i skolans kemisal.",severity:"tip"},{icon:"warning",title:"Fiberduk HELA säsongen",text:"Kålfjärilen flyger från maj till september. Lägg fiberduk vid utplantering och ta inte bort den förrän du skördar. Det är irriterande, men det funkar.",severity:"warning"},{icon:"harvest",title:"Nyttigare än vitkål",text:"Rödkål innehåller mer antioxidanter och C-vitamin än sin gröna kusin. Den djupa lila färgen kommer från antocyaniner - samma ämnen som gör blåbär och svarta vinbär så nyttiga.",severity:"tip"},{icon:"seedling",title:"Frost gör henne godare",text:"Rödkål tål frost bra och sena sorter kan stå kvar långt in på hösten. Lätt frost gör att sockret i bladen ökar - vinterns första frostknäpp förvandlar smaken till något alldeles speciellt.",severity:"tip"},{icon:"storage",title:"Syra rödkål - en svensk klassiker",text:"Rödkål kokt med äpple, ättika och kryddnejlika är en klassiker till julbordet. Men prova också att äta henne rå i sallader - krispig, söt och vackert lila. Eller fermentera som surkål!",severity:"tip"}],sowing:{method:"indoor",label:"Förodling inomhus",description:"Rödkål förodlas nästan alltid inomhus för att få tillräckligt lång säsong. Tidiga sorter kan direktsås i zon 1-3 men förodling ger bättre kontroll och tidigare skörd.",steps:["Så 1-2 cm djupt i krukor eller celler, 5-6 veckor före planerad utplantering","Håll jorden runt 18-20°C för snabb groning (5-10 dagar)","Flytta till svalare plats (12-15°C) och starkt ljus så snart plantorna är uppe - det ger kompakta, starka plantor","Gallra till en planta per cell om du sått flera frön","Härda av plantorna 7-10 dagar innan utplantering - ställ ut dagtid, in på natten","Plantera ut med 40-50 cm avstånd när plantan har 4-6 riktiga blad","Tryck till jorden ordentligt runt stammen, vattna rikligt och sätt kålkragar + fiberduk direkt"],tips:["Sena lagringssorter behöver förodlas redan i mars-april för att hinna mogna innan vintern","Tidiga sorter som Rodynda kan förodlas lite senare och ger skörd redan efter 70-90 dagar","Kålkragar runt stjälken vid utplantering skyddar mot kålfluga - gör dem av kartong, filt eller köp färdiga"],indoorWeeks:"5-6 veckor"},seedSaving:{difficulty:"Avancerad",type:"Korspollinerare",biennial:!0,description:"Rödkål är tvåårig - hon sätter frö först andra året. Huvudet måste övervintras och planteras ut igen på våren. En utmaning, men för den som vill bevara gamla sorter är det värt allt besvär.",steps:["Välj det finaste, friskaste huvudet med bäst färg och skörda det med roten kvar","Förvara hela plantan svalt (0-5°C) över vintern - källare eller jordkällare fungerar","Plantera ut igen på våren med intakt rot och huvudstump","Huvudet spricker upp och en blomstjälk växer upp ur mitten","Gula blommor pollineras av insekter - se till att bara EN sort av Brassica oleracea blommar","Låt fröskidorna mogna och torka på plantan tills de är bruna och spröda","Klipp av blomstjälkarna och eftertorka i papperspåse","Krossa skidorna försiktigt och blås bort agnarna. Förvara svalt och torrt."],isolation:"Korsar med ALLA andra Brassica oleracea (vitkål, grönkål, broccoli, blomkål, brysselkål, kålrabbi). Odla bara en sort för frö, eller isolera med minst 1 km.",storageYears:"4-5 år",tip:"Frötagning av rödkål kräver att du kan förvara en hel kålplanta över vintern. Välj OP-sorter som Langedijker Bewaar 2 eller Kalibos - de ger äkta avkomma. F1-hybrider som Integro ger inte sortriktiga frön."},storage:{shelfLife:"1-2 veckor (färsk), 3-6 månader (källare), 12 månader (syrad/fryst)",methods:[{method:"Källarlagring",icon:"storage",duration:"3-6 månader",description:"Sena lagringssorter som Langedijker Bewaar 2 hängs upp och ner i en sval källare (0-4°C) med roten kvar. Hög luftfuktighet (90-95%) är nyckeln. Rödkål lagrar generellt lika bra som vitkål.",best:!0},{method:"Kylskåp",icon:"snowflake",duration:"2-4 veckor",description:"Lägg i plastpåse med några hål i grönsakslådan. Hela huvuden håller längre än delad kål. Rödkål håller sig faktiskt lite bättre i kylskåp än vitkål tack vare de tätare bladen.",best:!1},{method:"Syra/inlägga",icon:"storage",duration:"6-12 månader",description:"Strimla kålen fint, koka med ättika, socker och kryddnejlika. Klassisk svensk inläggning som passar perfekt till julbordet och viltkött. Kan även fermenteras som surkål.",best:!1},{method:"Frysa",icon:"snowflake",duration:"8-12 månader",description:"Strimla, blanchera 1-2 minuter, kyl i isvatten och frys i portionspåsar. Perfekt för grytor och tillagade rätter. Texturen ändras men smaken och den fina färgen består.",best:!1},{method:"Torka",icon:"storage",duration:"6-12 månader",description:"Strimla tunt och torka i ugn på 50°C eller i torkmaskin. Kompakt och platssnålt. Färgen bleknar något men smaken håller sig bra.",best:!1}],tips:["Lagringssorter (Langedijker Bewaar 2) håller MYCKET längre än tidiga sorter - välj rätt sort om du vill lagra","Skörda lagringskål så sent som möjligt på hösten - gärna efter en lätt frost. Det förbättrar hållbarheten.","Häng kålhuvudena upp och ner i källaren med roten kvar - det förlänger lagringstiden rejält","Syrad rödkål är enklare att göra än du tror och resultatet blir fantastiskt till jul och höstmiddagar","Kontrollera lagrad kål regelbundet och ta bort blad som börjar bli sladdriga - resten av huvudet är ofta helt fint under"]},harvestCalc:{minPerSqm:2,maxPerSqm:6,unit:"kg"}};export{r as rodkal};
